// src/api/presenceApi.ts

import api from '@/lib/axios';

export interface UserPresence {
  userId: string;
  status: 'ONLINE' | 'OFFLINE' | 'AWAY';
  lastActiveAgo: string | null;
  lastSeen: string | null;
  isOnline: boolean;
}

export interface PresenceResponse {
  [userId: string]: UserPresence;
}

/**
 * Lấy presence của tất cả bạn bè
 */
export const getFriendsPresence = async (): Promise<PresenceResponse> => {
  const response = await api.get('/presence/friends');
  return response.data;
};

/**
 * Lấy presence của thành viên trong conversation
 */
export const getConversationPresence = async (conversationId: string): Promise<PresenceResponse> => {
  const response = await api.get(`/presence/conversation/${conversationId}`);
  return response.data;
};

/**
 * Lấy presence của một user cụ thể
 */
export const getUserPresence = async (userId: string): Promise<UserPresence | null> => {
  try {
    const response = await api.get(`/presence/user/${userId}`);
    return response.data;
  } catch (error: any) {
    if (error.response?.status === 404) {
      return null;
    }
    throw error;
  }
};

/**
 * Lấy presence của nhiều users
 */
export const getBatchPresence = async (userIds: string[]): Promise<PresenceResponse> => {
  const response = await api.post('/presence/batch', userIds);
  return response.data;
};

/**
 * Kiểm tra một user có online không
 */
export const checkUserOnline = async (userId: string): Promise<boolean> => {
  const response = await api.get(`/presence/check/${userId}`);
  return response.data.isOnline;
};

/**
 * Lấy danh sách tất cả users online
 */
export const getAllOnlineUsers = async (): Promise<string[]> => {
  const response = await api.get('/presence/online');
  return response.data;
};

import React, { useEffect } from 'react';
import { usePresenceStore } from '../store/presenceStore';
import { useAuthStore } from '../store/authStore';
import { chatWebSocketService } from '../services/chatWebSocketService';
import { logger } from '../utils/logger';

interface PresenceManagerProps {
  children: React.ReactNode;
}


export const PresenceManager: React.FC<PresenceManagerProps> = ({ children }) => {
  const { user, token } = useAuthStore();
  const { watchedUsers, addWatchedUser, removeWatchedUser } = usePresenceStore();

  const isAuthenticated = !!user && !!token;
  useEffect(() => {
    if (!isAuthenticated) return;

    const handleFocus = () => {
      logger.debug('[PresenceManager] Window focused - setting online status');
      if (chatWebSocketService.isConnected()) {
        chatWebSocketService.setOnlineStatus(true);
      }
    };

    const handleBlur = () => {
      logger.debug('[PresenceManager] Window blurred - could implement away status');
    };

    const handleBeforeUnload = () => {
      logger.debug('[PresenceManager] Window closing - setting offline status');
      if (chatWebSocketService.isConnected()) {
        chatWebSocketService.setOnlineStatus(false);
      }
    };

    window.addEventListener('focus', handleFocus);
    window.addEventListener('blur', handleBlur);
    window.addEventListener('beforeunload', handleBeforeUnload);

    return () => {
      window.removeEventListener('focus', handleFocus);
      window.removeEventListener('blur', handleBlur);
      window.removeEventListener('beforeunload', handleBeforeUnload);
    };
  }, [isAuthenticated]);

  // Handle visibility change for mobile devices
  useEffect(() => {
    if (!isAuthenticated) return;

    const handleVisibilityChange = () => {
      if (document.hidden) {
        logger.debug('[PresenceManager] Page hidden - could implement away status');
        // Optionally set away status
      } else {
        logger.debug('[PresenceManager] Page visible - setting online status');
        if (chatWebSocketService.isConnected()) {
          chatWebSocketService.setOnlineStatus(true);
        }
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [isAuthenticated]);
  useEffect(() => {
    if (!isAuthenticated || !chatWebSocketService.isConnected() || watchedUsers.size === 0) {
      console.debug('[PresenceManager] No watched users or not connected - skipping presence request');
      return;
    }

    const userIds = Array.from(watchedUsers);
    logger.debug('[PresenceManager] Requesting presence for watched users:', userIds);
    chatWebSocketService.requestOnlineStatus(userIds);
    chatWebSocketService.requestBatchOnlineStatus(userIds);
  }, [watchedUsers, isAuthenticated]);
  const watchUser = (userId: string) => {
    if (!userId || userId === user?.userId) return;
    
    logger.debug('[PresenceManager] Starting to watch user:', userId);
    addWatchedUser(userId);
  };

  const unwatchUser = (userId: string) => {
    if (!userId) return;
    
    logger.debug('[PresenceManager] Stopping to watch user:', userId);
    removeWatchedUser(userId);
  };

  const watchUsers = (userIds: string[]) => {
    const validUserIds = userIds.filter(id => id && id !== user?.userId);
    logger.debug('[PresenceManager] Starting to watch users:', validUserIds);
    
    validUserIds.forEach(userId => addWatchedUser(userId));
  };

  const unwatchUsers = (userIds: string[]) => {
    logger.debug('[PresenceManager] Stopping to watch users:', userIds);
    userIds.forEach(userId => removeWatchedUser(userId));
  };

  // Expose utility functions globally for easy access
  useEffect(() => {
    (window as any).presenceManager = {
      watchUser,
      unwatchUser,
      watchUsers,
      unwatchUsers,
    };

    return () => {
      delete (window as any).presenceManager;
    };
  }, [user]);

  return <>{children}</>;
};

export default PresenceManager;

import React, { useState, useCallback } from 'react';
import { X, Bell, User, MessageCircle, UserPlus, Heart } from 'lucide-react';

// Notification types
export type NotificationType = 'message' | 'friend_request' | 'reaction' | 'mention' | 'system';

export interface Notification {
  id: string;
  type: NotificationType;
  title: string;
  message: string;
  timestamp: Date;
  isRead: boolean;
  avatar?: string;
  userId?: string;
  conversationId?: string;
  data?: any; // Additional data for specific notification types
}

interface NotificationListProps {
  isOpen: boolean;
  onClose: () => void;
  notifications: Notification[];
  onMarkAsRead: (notificationId: string) => void;
  onMarkAllAsRead: () => void;
  onNotificationClick: (notification: Notification) => void;
}

const NotificationList: React.FC<NotificationListProps> = ({
  isOpen,
  onClose,
  notifications,
  onMarkAsRead,
  onMarkAllAsRead,
  onNotificationClick
}) => {
  const unreadCount = notifications.filter(n => !n.isRead).length;

  const getNotificationIcon = (type: NotificationType) => {
    switch (type) {
      case 'message':
        return <MessageCircle className="w-4 h-4 text-blue-500" />;
      case 'friend_request':
        return <UserPlus className="w-4 h-4 text-green-500" />;
      case 'reaction':
        return <Heart className="w-4 h-4 text-red-500" />;
      case 'mention':
        return <User className="w-4 h-4 text-purple-500" />;
      case 'system':
        return <Bell className="w-4 h-4 text-orange-500" />;
      default:
        return <Bell className="w-4 h-4 text-gray-500" />;
    }
  };

  const formatTimeAgo = (timestamp: Date) => {
    const now = new Date();
    const diffInMinutes = Math.floor((now.getTime() - timestamp.getTime()) / (1000 * 60));
    
    if (diffInMinutes < 1) return 'Vừa xong';
    if (diffInMinutes < 60) return `${diffInMinutes} phút trước`;
    
    const diffInHours = Math.floor(diffInMinutes / 60);
    if (diffInHours < 24) return `${diffInHours} giờ trước`;
    
    const diffInDays = Math.floor(diffInHours / 24);
    if (diffInDays < 7) return `${diffInDays} ngày trước`;
    
    return timestamp.toLocaleDateString('vi-VN');
  };

  const handleNotificationClick = (notification: Notification) => {
    if (!notification.isRead) {
      onMarkAsRead(notification.id);
    }
    onNotificationClick(notification);
  };

  if (!isOpen) return null;

  return (
    <div className="absolute top-12 right-0 w-80 max-h-96 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-lg shadow-lg z-50 overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 dark:border-gray-600">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Bell className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
              Thông báo
            </h3>
            {unreadCount > 0 && (
              <span className="bg-red-500 text-white text-xs rounded-full px-2 py-1">
                {unreadCount}
              </span>
            )}
          </div>
          <div className="flex items-center gap-2">
            {unreadCount > 0 && (
              <button
                onClick={onMarkAllAsRead}
                className="text-sm text-blue-600 dark:text-blue-400 hover:underline"
              >
                Đánh dấu tất cả đã đọc
              </button>
            )}
            <button
              onClick={onClose}
              className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>

      {/* Notification List */}
      <div className="max-h-80 overflow-y-auto">
        {notifications.length === 0 ? (
          <div className="p-8 text-center text-gray-500 dark:text-gray-400">
            <Bell className="w-12 h-12 mx-auto mb-3 opacity-50" />
            <p>Không có thông báo nào</p>
          </div>
        ) : (
          notifications.map((notification) => (
            <div
              key={notification.id}
              onClick={() => handleNotificationClick(notification)}
              className={`p-4 border-b border-gray-100 dark:border-gray-700 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors ${
                !notification.isRead ? 'bg-blue-50 dark:bg-blue-900/20' : ''
              }`}
            >
              <div className="flex items-start gap-3">
                {/* Avatar or Icon */}
                <div className="flex-shrink-0">
                  {notification.avatar ? (
                    <img
                      src={notification.avatar}
                      alt="Avatar"
                      className="w-8 h-8 rounded-full"
                    />
                  ) : (
                    <div className="w-8 h-8 bg-gray-200 dark:bg-gray-600 rounded-full flex items-center justify-center">
                      {getNotificationIcon(notification.type)}
                    </div>
                  )}
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <h4 className="text-sm font-medium text-gray-900 dark:text-white truncate">
                      {notification.title}
                    </h4>
                    {!notification.isRead && (
                      <div className="w-2 h-2 bg-blue-500 rounded-full flex-shrink-0"></div>
                    )}
                  </div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-2 mt-1">
                    {notification.message}
                  </p>
                  <p className="text-xs text-gray-500 dark:text-gray-500 mt-2">
                    {formatTimeAgo(notification.timestamp)}
                  </p>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

// Notification Hook
export const useNotifications = () => {
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((notification: Omit<Notification, 'id' | 'timestamp' | 'isRead'>) => {
    const newNotification: Notification = {
      ...notification,
      id: crypto.randomUUID(),
      timestamp: new Date(),
      isRead: false
    };
    
    setNotifications(prev => [newNotification, ...prev]);
  }, []);

  const markAsRead = useCallback((notificationId: string) => {
    setNotifications(prev =>
      prev.map(n =>
        n.id === notificationId ? { ...n, isRead: true } : n
      )
    );
  }, []);

  const markAllAsRead = useCallback(() => {
    setNotifications(prev =>
      prev.map(n => ({ ...n, isRead: true }))
    );
  }, []);

  const removeNotification = useCallback((notificationId: string) => {
    setNotifications(prev =>
      prev.filter(n => n.id !== notificationId)
    );
  }, []);

  const clearAll = useCallback(() => {
    setNotifications([]);
  }, []);

  return {
    notifications,
    addNotification,
    markAsRead,
    markAllAsRead,
    removeNotification,
    clearAll
  };
};

// Notification Button Component
interface NotificationButtonProps {
  notifications: Notification[];
  isOpen: boolean;
  onClick: () => void;
}

export const NotificationButton: React.FC<NotificationButtonProps> = ({
  notifications,
  isOpen,
  onClick
}) => {
  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <button
      onClick={onClick}
      className={`relative p-2 rounded-lg transition-colors ${
        isOpen
          ? 'bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-400'
          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700'
      }`}
    >
      <Bell className="w-5 h-5" />
      {unreadCount > 0 && (
        <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full min-w-[18px] h-[18px] flex items-center justify-center">
          {unreadCount > 99 ? '99+' : unreadCount}
        </span>
      )}
    </button>
  );
};

export default NotificationList;

import * as React from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';

const badgeVariants = cva(
  'inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2',
  {
    variants: {
      variant: {
        default:
          'border-transparent bg-blue-600 text-white dark:bg-blue-400 dark:text-gray-900',
        secondary:
          'border-transparent bg-gray-200 text-gray-900 dark:bg-gray-700 dark:text-gray-100',
        destructive:
          'border-transparent bg-red-600 text-white dark:bg-red-500 dark:text-white',
        outline:
          'text-gray-900 dark:text-gray-50 border border-gray-300 dark:border-gray-700 bg-transparent',
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  }
);

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  );
}

export { Badge, badgeVariants };

// src/context/AuthContext.tsx
import { createContext, useContext } from 'react';
import { useAuthStore } from '@/store/authStore';

// Tạo context cho các component cần truy cập trực tiếp
const AuthContext = createContext(useAuthStore.getState());

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const authState = useAuthStore();
  
  return (
    <AuthContext.Provider value={authState}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

// src/hooks/useChatWebSocket.ts

import { useEffect, useRef, useCallback } from 'react';
import { chatWebSocketService } from '@/services/chatWebSocketService';
import { debounce } from '@/utils/debounce';
import type {
  TypingEventReceived,
  OnlineStatusResponse,
  PresenceEvent,
  NotificationReceived,
} from '@/types/websocket';
import type { MessageResponseDto } from '@/types/message';

interface UseChatWebSocketOptions {
  onMessageReceived?: (message: MessageResponseDto) => void;
  onTypingReceived?: (event: TypingEventReceived) => void;
  onOnlineStatusReceived?: (event: OnlineStatusResponse) => void;
  onPresenceReceived?: (event: PresenceEvent) => void;
  onNotificationReceived?: (event: NotificationReceived) => void;
}

export const useChatWebSocket = (options: UseChatWebSocketOptions = {}) => {
  const {
    onMessageReceived,
    onTypingReceived,
    onOnlineStatusReceived,
    onPresenceReceived,
    onNotificationReceived,
  } = options;

  

  const subscribedConversations = useRef<Set<string>>(new Set());

  // Message operations
  const sendMessage = useCallback((payload: Parameters<typeof chatWebSocketService.sendMessage>[0]) => {
    chatWebSocketService.sendMessage(payload);
  }, []);

  const subscribeToConversation = useCallback((conversationId: string) => {
    if (subscribedConversations.current.has(conversationId)) {
      console.log('[subscribeToConversation] ⚠️ Already subscribed to:', conversationId);
      return; // Already subscribed
    }

    console.log('📡 [MessageWebSocket] Subscribed to conversation:', conversationId);
    console.log('[subscribeToConversation] WebSocket connected:', chatWebSocketService.isConnected());
    console.log('[subscribeToConversation] 📢 Topic for ALL PARTICIPANTS: /topic/conversation/' + conversationId);

    chatWebSocketService.subscribeToMessages(conversationId, (message) => {
      console.log('🔔 [WebSocket] Message received from CONVERSATION topic /topic/conversation/' + conversationId + ':', message);
      console.log('🔔 [WebSocket] This is for ALL PARTICIPANTS in conversation');
      console.log('🔔 [WebSocket] Message details:', {
       message
      });
      onMessageReceived?.(message);
      console.log('🔔 [WebSocket] Message callback executed successfully');
    });
    
    // Subscribe to typing events for this conversation
    if (onTypingReceived) {
      chatWebSocketService.subscribeToTyping(conversationId, onTypingReceived);
    }
    
    subscribedConversations.current.add(conversationId);
  }, [onMessageReceived, onTypingReceived]);

  const unsubscribeFromConversation = useCallback((conversationId: string) => {
    if (!subscribedConversations.current.has(conversationId)) {
      console.log('[unsubscribeFromConversation] ⚠️ Not subscribed to:', conversationId);
      return; // Not subscribed
    }
    
    console.log('🔁 [MessageWebSocket] Unsubscribing from conversation:', conversationId);
    chatWebSocketService.unsubscribeFromMessages(conversationId);
    chatWebSocketService.unsubscribeFromTyping(conversationId);
    subscribedConversations.current.delete(conversationId);
    console.log('[unsubscribeFromConversation] Conversation removed from tracked list:', conversationId);
  }, []);

  // Typing operations
  const sendTyping = useCallback((conversationId: string, isTyping: boolean) => {
    chatWebSocketService.sendTyping(conversationId, isTyping);
  }, []);

  // Online status operations with debounce optimization using useRef for stability
  // Create stable debounced function reference
  const debouncedSetOnlineStatusRef = useRef<((isOnline: boolean) => void) | null>(null);
  
  // Only create debounced function once
  useEffect(() => {
    if (!debouncedSetOnlineStatusRef.current) {
      debouncedSetOnlineStatusRef.current = debounce((isOnline: boolean) => {
        console.log('[setOnlineStatus] Debounced call with:', isOnline);
        chatWebSocketService.sendHeartbeat();
      }, 300); // 300ms debounce delay
    }
  }, []);
  
  const setOnlineStatus = useCallback((isOnline: boolean) => {
    console.log('[setOnlineStatus] Setting online status:', isOnline);
    debouncedSetOnlineStatusRef.current?.(isOnline);
  }, []);

  const requestOnlineStatus = useCallback((userIds: string[]) => {
    chatWebSocketService.requestOnlineStatus(userIds);
  }, []);

  // Enhanced presence operations
  const sendHeartbeat = useCallback(() => {
    chatWebSocketService.sendHeartbeat();
  }, []);

  // const subscribeToPresence = useCallback((callback: (event: any) => void) => {
  //   chatWebSocketService.subscribeToPresenceUpdates(callback);
  // }, []);

  const unsubscribeFromPresence = useCallback(() => {
    chatWebSocketService.unsubscribeFromPresenceUpdates();
  }, []);

  // Notification operations
  const markNotificationAsRead = useCallback((notificationId: string) => {
    chatWebSocketService.markNotificationAsRead(notificationId);
  }, []);

  // Utility methods
  const isConnected = useCallback(() => {
    return chatWebSocketService.isConnected();
  }, []);

  const getActiveSubscriptions = useCallback(() => {
    return chatWebSocketService.getActiveSubscriptions();
  }, []);

  // Track subscription states to prevent duplicates
  const subscriptionStates = useRef({
    onlineStatus: false,
    presence: false,
    notifications: false
  });

  // Stable callback refs to prevent re-subscriptions
  const onlineStatusCallbackRef = useRef(onOnlineStatusReceived);
  const presenceCallbackRef = useRef(onPresenceReceived);
  const notificationCallbackRef = useRef(onNotificationReceived);

  // Update callback refs when props change
  useEffect(() => {
    onlineStatusCallbackRef.current = onOnlineStatusReceived;
  }, [onOnlineStatusReceived]);

  useEffect(() => {
    presenceCallbackRef.current = onPresenceReceived;
  }, [onPresenceReceived]);

  useEffect(() => {
    notificationCallbackRef.current = onNotificationReceived;
  }, [onNotificationReceived]);

  // Setup global subscriptions - only once per hook instance
  useEffect(() => {
    let isSetupComplete = false;

    const setupSubscriptions = () => {
      // Only setup subscriptions if connected and not already set up
      if (!isConnected() || isSetupComplete) return;

      console.log('[WebSocket] Setting up global subscriptions...');
      if (onlineStatusCallbackRef.current && !subscriptionStates.current.onlineStatus) {
        console.log('[WebSocket] Setting up online status subscription');
        chatWebSocketService.subscribeToOnlineStatus((event) => {
          onlineStatusCallbackRef.current?.(event);
        });
        subscriptionStates.current.onlineStatus = true;
      }

      if (presenceCallbackRef.current && !subscriptionStates.current.presence) {
        console.log('[WebSocket] Setting up presence subscription');
        chatWebSocketService.subscribeToPresence((event) => {
          presenceCallbackRef.current?.(event);
        });
        subscriptionStates.current.presence = true;
      }

      if (notificationCallbackRef.current && !subscriptionStates.current.notifications) {
        console.log('[WebSocket] Setting up notifications subscription');
        chatWebSocketService.subscribeToNotifications((event) => {
          notificationCallbackRef.current?.(event);
        });
        subscriptionStates.current.notifications = true;
      }

      isSetupComplete = true;
    };

    // Initial setup
    setupSubscriptions();

    // Cleanup on unmount only
    return () => {
      console.log('[WebSocket] Hook cleanup - unsubscribing from all global subscriptions');
      
      // Unsubscribe from all conversations
      subscribedConversations.current.forEach((conversationId) => {
        chatWebSocketService.unsubscribeFromMessages(conversationId);
        chatWebSocketService.unsubscribeFromTyping(conversationId);
      });
      subscribedConversations.current.clear();

      // Unsubscribe from global events and reset states
      if (subscriptionStates.current.onlineStatus) {
        console.log('[WebSocket] Cleaning up online status subscription');
        chatWebSocketService.unsubscribeFromOnlineStatus();
        subscriptionStates.current.onlineStatus = false;
      }
      if (subscriptionStates.current.presence) {
        console.log('[WebSocket] Cleaning up presence subscription');
        chatWebSocketService.unsubscribeFromPresence();
        subscriptionStates.current.presence = false;
      }
      if (subscriptionStates.current.notifications) {
        console.log('[WebSocket] Cleaning up notifications subscription');
        chatWebSocketService.unsubscribeFromNotifications();
        subscriptionStates.current.notifications = false;
      }
    };
  }, []); // Empty dependency array - chỉ chạy một lần

  return {
    // Message operations
    sendMessage,
    subscribeToConversation,
    unsubscribeFromConversation,
    
    // Typing operations
    sendTyping,
    
    // Online status operations
    setOnlineStatus,
    requestOnlineStatus,
    
    // Enhanced presence operations
    sendHeartbeat,
    // subscribeToPresence,
    unsubscribeFromPresence,
    
    // Notification operations
    markNotificationAsRead,
    
    // Utility methods
    isConnected,
    getActiveSubscriptions,
    
    // State
    subscribedConversations: Array.from(subscribedConversations.current),
  };
};

// Specialized hooks for specific features
export const useMessageWebSocket = (
  conversationId: string, 
  onMessageReceived: (message: MessageResponseDto) => void,
  onEchoReceived?: (echo: MessageResponseDto) => void
) => {
  console.log('🚀 [useMessageWebSocket] Hook initialized with:', {
    conversationId,
    hasOnMessageReceived: !!onMessageReceived,
    hasOnEchoReceived: !!onEchoReceived
  });

  const chatWebSocket = useChatWebSocket({
    onMessageReceived: (message) => {
      onMessageReceived(message);
    },
  });

  const {  subscribeToConversation, unsubscribeFromConversation, isConnected } = chatWebSocket;

  useEffect(() => {
    console.log('🔧 [useMessageWebSocket] Effect triggered:', {
      conversationId,
      isConnected: isConnected(),
      hasCallbacks: !!onMessageReceived
    });

    if (conversationId && isConnected()) {
      subscribeToConversation(conversationId);
      
      // Subscribe to message echo for immediate feedback
      if (onEchoReceived) {
        chatWebSocketService.subscribeToMessageEcho((echo) => {
          console.log('🔊 [useMessageWebSocket] Echo received:', echo);
          onEchoReceived(echo);
        });
      }
      
      return () => {
        unsubscribeFromConversation(conversationId);
        if (onEchoReceived) {
          console.log('🔧 [useMessageWebSocket] Cleanup: unsubscribing from message echo');
          chatWebSocketService.unsubscribeFromMessageEcho();
        }
      };
    } else {
      console.log('🔧 [useMessageWebSocket] Not subscribing:', {
        hasConversationId: !!conversationId,
        isConnected: isConnected()
      });
    }
  }, [conversationId, subscribeToConversation, unsubscribeFromConversation, onEchoReceived, isConnected]);


};



