// src/hooks/useMessages.ts

import { useState, useEffect, useCallback } from 'react';
import { getLatestMessages, getOlderMessages } from '@/api/messageApi';
import type { MessageResponseDto } from '@/types/message';

interface UseMessagesOptions {
  conversationId?: string;
  limit?: number;
  autoRefresh?: boolean;
}

export const useMessages = (options: UseMessagesOptions = {}) => {
  const { conversationId, limit = 20, autoRefresh = false } = options; // Changed default from 50 to 20
  
  const [messages, setMessages] = useState<MessageResponseDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(true);

  const fetchMessages = useCallback(async (beforeMessageId?: string) => {
    if (!conversationId) {
      console.log('[useMessages] No conversationId provided');
      return;
    }

    const token = localStorage.getItem('token');
    if (!token) {
      setError('No authentication token found');
      console.error('[useMessages] No token found');
      return;
    }

    console.log('[useMessages] 🚀 Fetching messages for conversation:', conversationId);
    console.log('[useMessages] 📊 Request type:', beforeMessageId ? 'LOAD_MORE (older)' : 'INITIAL_LOAD (latest)');
    setLoading(true);
    setError(null);

    try {
      let response: MessageResponseDto[];
      
      if (beforeMessageId) {
        // Load older messages (30 messages)
        console.log('[useMessages] Loading older messages before:', beforeMessageId);
        response = await getOlderMessages(token, conversationId, beforeMessageId);
      } else {
        // Initial load (20 messages)
        console.log('[useMessages] Loading latest messages with limit:', limit);
        response = await getLatestMessages(token, conversationId, limit);
      }
      
      console.log('[useMessages] Received messages:', response);
      
      if (beforeMessageId) {
        // Load more messages (append to beginning, but check for duplicates)
        setMessages(prev => {
          const existingIds = new Set(prev.map(m => m.messageId));
          const newMessages = response.filter(m => !existingIds.has(m.messageId));
          console.log(`[useMessages] 🔄 Adding ${newMessages.length} new older messages (filtered ${response.length - newMessages.length} duplicates)`);
          return [...newMessages, ...prev];
        });
        setHasMore(response.length === 30); // For older messages, we load 30 at a time
      } else {
        // Initial load or refresh (replace all messages)
        setMessages(response);
        setHasMore(response.length === limit);
      }
    } catch (err) {
      console.error('[useMessages] Error fetching messages:', err);
      setError(err instanceof Error ? err.message : 'Failed to fetch messages');
    } finally {
      setLoading(false);
    }
  }, [conversationId, limit]);

  const loadMoreMessages = useCallback(() => {
    if (messages.length > 0 && hasMore && !loading) {
      const oldestMessage = messages[0];
      console.log('[useMessages] 🔄 Loading more messages before messageId:', oldestMessage.messageId);
      console.log('[useMessages] 📊 Current messages count:', messages.length, '- Will load 30 more');
      fetchMessages(oldestMessage.messageId); // Use messageId instead of createdAt
    } else {
      console.log('[useMessages] ❌ Cannot load more:', {
        hasMessages: messages.length > 0,
        hasMore,
        loading
      });
    }
  }, [messages, hasMore, loading, fetchMessages]);

  const addMessage = useCallback((message: MessageResponseDto) => {
    console.log('🟢 [useMessages] addMessage called with:', message);
    setMessages(prev => {
      // Check for duplicates
      const isDuplicate = prev.some(m => m.messageId === message.messageId);
      if (isDuplicate) {
        console.log('⚠️ [useMessages] Duplicate message detected, skipping:', message.messageId);
        return prev;
      }
      
      console.log('✅ [useMessages] Adding new message:', message.messageId);
      return [...prev, message];
    });
  }, []);

  const updateMessage = useCallback((messageId: string, updates: Partial<MessageResponseDto>) => {
    setMessages(prev => 
      prev.map(msg => 
        msg.messageId === messageId ? { ...msg, ...updates } : msg
      )
    );
  }, []);

  const removeMessage = useCallback((messageId: string) => {
    setMessages(prev => prev.filter(msg => msg.messageId !== messageId));
  }, []);

  // ✅ Auto-fetch tin nhắn khi conversationId thay đổi (load 20 tin mới nhất)
  // Initial fetch when conversationId changes
  useEffect(() => {
    console.log('[useMessages] ConversationId changed to:', conversationId);
    
    if (conversationId) {
      console.log('[useMessages] ✅ Clearing previous messages and loading initial 20 messages');
      setMessages([]); // ✅ Clear previous messages immediately
      setError(null);
      setHasMore(true);
      fetchMessages(); // ✅ Auto-fetch 20 tin nhắn mới nhất khi vào room
    } else {
      console.log('[useMessages] No conversationId, clearing messages');
      setMessages([]);
      setError(null);
      setHasMore(true);
    }
  }, [conversationId]); // ✅ Remove fetchMessages from deps to avoid recreation loop

  // Auto refresh if enabled
  useEffect(() => {
    if (!autoRefresh || !conversationId) return;

    const interval = setInterval(() => {
      fetchMessages();
    }, 30000); // Refresh every 30 seconds

    return () => clearInterval(interval);
  }, [autoRefresh, conversationId, fetchMessages]);

  return {
    messages,
    loading,
    error,
    hasMore,
    fetchMessages,
    loadMoreMessages,
    addMessage,
    updateMessage,
    removeMessage,
    refresh: () => fetchMessages(), // Initial load without beforeMessageId
  };
};

import { useCallback, useRef } from 'react';

export function useDebounce<T extends (...args: any[]) => void>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);
  
  return useCallback((...args: Parameters<T>) => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
    timeoutRef.current = setTimeout(() => func(...args), delay);
  }, [func, delay]);
}

