export const useRoomActions = (conversation: Conversation) => {
  const { user } = useAuthStore();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Room members
  const [members, setMembers] = useState<RoomMember[]>([]);
  const [loadingMembers, setLoadingMembers] = useState(false);

  // Pinned messages
  const [pinnedMessages, setPinnedMessages] = useState<PinnedMessage[]>([]);
  const [loadingPinned, setLoadingPinned] = useState(false);

  // User profile
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingProfile, setLoadingProfile] = useState(false);

  const currentUserMember = members.find(m => m.userId === user?.user_id);
  const currentUserRole = currentUserMember?.role || 'member';

  // Load room members
  const loadMembers = useCallback(async () => {
    if (!conversation.conversationId) return;

    setLoadingMembers(true);
    try {
      const roomMembers = await roomApi.getMembers(conversation.conversationId);
      setMembers(roomMembers);
    } catch (err: any) {
      setError(err.message || 'Failed to load members');
    } finally {
      setLoadingMembers(false);
    }
  }, [conversation.conversationId]);

  // Load pinned messages
  const loadPinnedMessages = useCallback(async () => {
    if (!conversation.conversationId) return;

    setLoadingPinned(true);
    try {
      const pinned = await roomApi.getPinnedMessages(conversation.conversationId);
      setPinnedMessages(pinned);
    } catch (err: any) {
      setError(err.message || 'Failed to load pinned messages');
    } finally {
      setLoadingPinned(false);
    }
  }, [conversation.conversationId]);

  // Load user profile
  const loadUserProfile = useCallback(async (userId: string) => {
    setLoadingProfile(true);
    try {
      const profile = await roomApi.getUserProfile(userId);
      setUserProfile(profile);
    } catch (err: any) {
      setError(err.message || 'Failed to load user profile');
    } finally {
      setLoadingProfile(false);
    }
  }, []);

  // Update room settings
  const updateRoomSettings = useCallback(async (settings: Partial<RoomSettings>) => {
    if (!conversation.conversationId) return;

    setLoading(true);
    try {
      await roomApi.updateRoomSettings(conversation.conversationId, settings);
      // Optionally update local conversation state
    } catch (err: any) {
      setError(err.message || 'Failed to update room settings');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [conversation.conversationId]);

  // Perform member action
  const performMemberAction = useCallback(async (memberId: string, action: RoomActionType, reason?: string) => {
    if (!conversation.conversationId) return;

    setLoading(true);
    try {
      await roomApi.performMemberAction(conversation.conversationId, memberId, action, reason);
      
      // Update local members state based on action
      if (action === 'KICK_MEMBER' || action === 'BAN_MEMBER') {
        setMembers(prev => prev.filter(m => m.userId !== memberId));
      } else if (action === 'PROMOTE_TO_ADMIN') {
        setMembers(prev => prev.map(m => 
          m.userId === memberId ? { ...m, role: 'admin' } : m
        ));
      } else if (action === 'PROMOTE_TO_MODERATOR') {
        setMembers(prev => prev.map(m => 
          m.userId === memberId ? { ...m, role: 'moderator' } : m
        ));
      } else if (action === 'DEMOTE_FROM_ADMIN' || action === 'DEMOTE_FROM_MODERATOR') {
        setMembers(prev => prev.map(m => 
          m.userId === memberId ? { ...m, role: 'member' } : m
        ));
      }
    } catch (err: any) {
      setError(err.message || 'Failed to perform action');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [conversation.conversationId]);

  // Pin message
  const pinMessage = useCallback(async (messageId: string) => {
    setLoading(true);
    try {
      await roomApi.pinMessage(messageId);
      await loadPinnedMessages(); // Reload pinned messages
    } catch (err: any) {
      setError(err.message || 'Failed to pin message');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [loadPinnedMessages]);

  // Unpin message
  const unpinMessage = useCallback(async (messageId: string) => {
    setLoading(true);
    try {
      await roomApi.unpinMessage(messageId);
      setPinnedMessages(prev => prev.filter(p => p.messageId !== messageId));
    } catch (err: any) {
      setError(err.message || 'Failed to unpin message');
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  // Navigate to message
  const goToMessage = useCallback((messageId: string) => {
    // This should scroll to the message in the chat
    console.log('Navigating to message:', messageId);
  }, []);

  // Leave room
  const leaveRoom = useCallback(async () => {
    if (!conversation.conversationId || !user) return;

    setLoading(true);
    try {
      await roomApi.performMemberAction(conversation.conversationId, user.user_id, 'KICK_MEMBER');
      // Handle navigation away from room
    } catch (err: any) {
      setError(err.message || 'Failed to leave room');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [conversation.conversationId, user]);

  // Dissolve room
  const dissolveRoom = useCallback(async () => {
    if (!conversation.conversationId) return;

    setLoading(true);
    try {
      await roomApi.performMemberAction(conversation.conversationId, '', 'DISSOLVE_ROOM');
      // Handle navigation away from room
    } catch (err: any) {
      setError(err.message || 'Failed to dissolve room');
      throw err;
    } finally {
      setLoading(false);
    }
  }, [conversation.conversationId]);

  const clearError = useCallback(() => {
    setError(null);
  }, []);

  return {
    // State
    members,
    pinnedMessages,
    userProfile,
    currentUserRole,
    loading,
    loadingMembers,
    loadingPinned,
    loadingProfile,
    error,

    // Actions
    loadMembers,
    loadPinnedMessages,
    loadUserProfile,
    updateRoomSettings,
    performMemberAction,
    pinMessage,
    unpinMessage,
    goToMessage,
    leaveRoom,
    dissolveRoom,
    clearError,

    // Computed
    isAdmin: currentUserRole === 'admin',
    isModerator: currentUserRole === 'moderator',
    canManageRoom: currentUserRole === 'admin' || currentUserRole === 'moderator'
  };
};

// src/services/chatWebSocketService.ts

import { getStompClient } from './websocketService';
import { logger } from '../utils/logger';
import type {
  TypingEvent,
  TypingEventReceived,
  OnlineStatusResponse,
  PresenceEvent,
  NotificationReceived,
} from '@/types/websocket';
import {
  WS_TOPICS,
  WS_DESTINATIONS,
  isMessageEvent,
  isTypingEvent,
  isOnlineStatusEvent,
  isPresenceEvent,
  isNotificationEvent,
} from '@/types/websocket';
import type { MessageResponseDto, SendMessageWsPayload } from '@/types/message';
import type { StompSubscription } from '@stomp/stompjs';

export class ChatWebSocketService {
  private subscriptions: Map<string, StompSubscription> = new Map();
  private get stompClient() {
    return getStompClient();
  }

  // Helper function để lấy Authorization header
  public getAuthHeaders(): { [key: string]: string } {
    const token = localStorage.getItem('token');
    if (token) {
      return { 'Authorization': `Bearer ${token}` };
    }
    return {};
  }

  // 📨 Message operations
  sendMessage(payload: SendMessageWsPayload ): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }
    if (!payload.payload?.conversationId) {
      logger.error('Invalid payload: missing conversationId');
      return;
    }
    let destination: string = WS_DESTINATIONS.MESSAGE_SEND; 
    
    if (payload.type === 'NEW_MESSAGE' && payload.payload.type === 'FILE') {
      destination = WS_DESTINATIONS.MESSAGE_FILE; 
    }
    
    const headers = this.getAuthHeaders();
    this.stompClient.publish({
      destination,
      body: JSON.stringify(payload),
      headers: headers,
    });
  }
  

  subscribeToMessages(
    conversationId: string,
    callback: (message: MessageResponseDto) => void
  ): void {
    if (!this.stompClient?.connected) {
      logger.warn('[subscribeToMessages] WebSocket is not connected');
      return;
    }
    const conversationKey = `conversation_${conversationId}`;
    const topic = WS_TOPICS.CONVERSATION(conversationId);
    if (this.subscriptions.has(conversationKey)) {
      logger.debug('[subscribeToMessages] Already subscribed to conversation:', conversationId);
      return;
    }
    
    
    const subscription = this.stompClient.subscribe(topic, (frame) => {
      
      try {
        const data = JSON.parse(frame.body);
        
        if (isMessageEvent(data)) {
          logger.debug('[subscribeToMessages] Valid message event received');
          callback(data);
        } else {
          logger.debug('[subscribeToMessages] Invalid message event format');
        }
      } catch (error) {
        logger.error('[subscribeToMessages] Error parsing message event:', error);
      }
    });

    this.subscriptions.set(conversationKey, subscription);
    logger.debug('[subscribeToMessages] Subscription created for conversation:', conversationId);
  }

  subscribeToMessageEcho(callback: (message: MessageResponseDto) => void): void {
    if (!this.stompClient?.connected) {
      logger.warn('[subscribeToMessageEcho] WebSocket is not connected');
      return;
    }

    const subscription = this.stompClient.subscribe(WS_TOPICS.MESSAGE_ECHO, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        if (isMessageEvent(data)) {
          logger.debug('[subscribeToMessageEcho] Valid echo message received');
          callback(data);
        } else {
          logger.debug('[subscribeToMessageEcho] Invalid echo message format');
        }
      } catch (error) {
        logger.error('[subscribeToMessageEcho] Error parsing message echo:', error);
      }
    });

    this.subscriptions.set('message-echo', subscription);
  }

  // Subscribe to error messages
  subscribeToErrors(callback: (error: string) => void): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }

    logger.debug('Subscribing to errors');
    const subscription = this.stompClient.subscribe(WS_TOPICS.ERRORS, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        logger.error('Received WebSocket error:', data);
        callback(data);
      } catch (error) {
        logger.error('Error parsing error message:', error);
      }
    });

    this.subscriptions.set('errors', subscription);
  }

  unsubscribeFromMessageEcho(): void {
    const subscription = this.subscriptions.get('message-echo');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('message-echo');
    }
  }

  unsubscribeFromErrors(): void {
    const subscription = this.subscriptions.get('errors');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('errors');
    }
  }

  unsubscribeFromMessages(conversationId: string): void {
    const key = `conversation_${conversationId}`;
    const subscription = this.subscriptions.get(key);
    
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete(key);
      logger.debug('[unsubscribeFromMessages] Successfully unsubscribed from:', conversationId);
    } else {
      logger.debug('[unsubscribeFromMessages] No subscription found for:', conversationId);
    }
  }

  // ⌨️ Typing operations
  sendTyping(conversationId: string, isTyping: boolean): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }
    const payload: TypingEvent = { conversationId, isTyping };
    const headers = this.getAuthHeaders();
    
    this.stompClient.publish({
      destination: WS_DESTINATIONS.TYPING,
      body: JSON.stringify(payload),
      headers: headers,
    });
  }

  subscribeToTyping(conversationId: string, callback: (event: TypingEventReceived) => void): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }

    const typingKey = `typing_${conversationId}`;
    const topic = WS_TOPICS.CONVERSATION_TYPING(conversationId);
    
    if (this.subscriptions.has(typingKey)) {
      return;
    }
    const subscription = this.stompClient.subscribe(topic, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        if (isTypingEvent(data)) {
          callback(data);
        }
      } catch (error) {
        logger.error('Error parsing typing event:', error);
      }
    });

    this.subscriptions.set(typingKey, subscription);
    logger.debug('Successfully subscribed to typing events for conversation:', conversationId);
  }

  requestOnlineStatus(userIds: string[]): void {

    this.requestBatchOnlineStatus(userIds);
  }

  subscribeToOnlineStatus(callback: (event: OnlineStatusResponse) => void): void {
    logger.info('[WebSocket] subscribeToOnlineStatus called');
    
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot subscribe to online status - not connected');
      return;
    }

    // Check if already subscribed (avoid duplicate with presence events)
    if (this.subscriptions.has('online_status')) {
      logger.debug('[WebSocket] Already subscribed to online status');
      return;
    }

    logger.debug('[WebSocket] Subscribing to online status');
    
    const subscription = this.stompClient.subscribe(WS_TOPICS.ONLINE_STATUS, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        logger.debug('[WebSocket] Received online status event:', data);
        
        if (isOnlineStatusEvent(data)) {
          callback(data);
        } else {
          console.log('⚠️ [SUBSCRIBE-ONLINE] Invalid online status event format:', data);
        }
      } catch (error) {
        console.error('❌ [SUBSCRIBE-ONLINE] Error parsing online status event:', error);
        logger.error('Error parsing online status event:', error);
      }
    });

    this.subscriptions.set('online_status', subscription);
    logger.debug('[WebSocket] Online status subscription created');
  }

  sendHeartbeat(deviceInfo?: string, sessionId?: string): void {
    logger.info('[WebSocket] sendHeartbeat called');
    
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot send heartbeat - not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    const payload: any = {
      timestamp: Date.now(),
    };
    
    if (sessionId) {
      payload.sessionId = sessionId;
    }
    
    if (deviceInfo) {
      payload.deviceInfo = deviceInfo;
    }
    
    
    this.stompClient.publish({
      destination: WS_DESTINATIONS.PRESENCE_HEARTBEAT,
      body: JSON.stringify(payload),
      headers: headers,
    });
    logger.debug('[WebSocket] Heartbeat sent');
  }

  unsubscribeFromPresenceUpdates(): void {
    const subscription = this.subscriptions.get('presence_updates');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('presence_updates');
      logger.debug('[WebSocket] Unsubscribed from presence updates');
    }
  }

  // 👥 Presence operations
  subscribeToPresence(callback: (event: PresenceEvent) => void): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot subscribe to presence - not connected');
      return;
    }

    // Check if already subscribed
    if (this.subscriptions.has('presence')) {
      logger.debug('[WebSocket]Already subscribed to presence');
      return;
    }

    logger.debug('[WebSocket] Subscribing to presence');
    const subscription = this.stompClient.subscribe(WS_TOPICS.PRESENCE, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        if (isPresenceEvent(data)) {
          callback(data);
        }
      } catch (error) {
        logger.error('Error parsing presence event:', error);
      }
    });

    this.subscriptions.set('presence', subscription);
    logger.debug('[WebSocket] Presence subscription created');
  }

  markNotificationAsRead(notificationId: string): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    
    this.stompClient.publish({
      destination: '/app/notification.read',
      body: JSON.stringify({ notificationId }),
      headers: headers,
    });
    
    logger.debug('[WebSocket] Marked notification as read:', notificationId);
  }

  markAllNotificationsAsRead(): void {
    if (!this.stompClient?.connected) {
      logger.warn('WebSocket is not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    
    this.stompClient.publish({
      destination: '/app/notifications.read-all',
      body: JSON.stringify({}),
      headers: headers,
    });
    
    logger.debug('[WebSocket] Marked all notifications as read');
  }

  subscribeToNotifications(callback: (event: NotificationReceived) => void): void {
    if (!this.stompClient?.connected) {
      console.warn('[WebSocket] Cannot subscribe to notifications - not connected');
      return;
    }

    // Check if already subscribed
    if (this.subscriptions.has('notifications')) {
      console.log('[WebSocket] Already subscribed to notifications, skipping duplicate subscription');
      return;
    }

    console.log('[WebSocket] >>> SUBSCRIBE to notifications');
    const subscription = this.stompClient.subscribe(WS_TOPICS.NOTIFICATIONS, (frame) => {
      try {
        const data = JSON.parse(frame.body);
        if (isNotificationEvent(data)) {
          callback(data);
        }
      } catch (error) {
        console.error('Error parsing notification event:', error);
      }
    });

    this.subscriptions.set('notifications', subscription);
    console.log('[WebSocket] Notifications subscription created successfully');
  }

  // Generic publish method for advanced usage
  public publish(destination: string, body: string, headers?: { [key: string]: string }): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot publish - not connected');
      return;
    }

    const mergedHeaders = { ...this.getAuthHeaders(), ...headers };
    
    this.stompClient.publish({
      destination,
      body: JSON.stringify(body),
      headers: mergedHeaders,
    });
    
    logger.debug('[WebSocket] Published to:', destination);
  }

  // 🚀 Optimized presence methods for backend integration
  subscribeToPresenceEvents(): void {
    logger.info('[WebSocket] subscribeToPresenceEvents called');
    
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot subscribe to presence events - not connected');
      return;
    }

    // Subscribe to personalized online status queue
    if (!this.subscriptions.has('online_status_queue')) {
      logger.debug('[WebSocket] Subscribing to personalized online status queue');
      
      const subscription = this.stompClient.subscribe('/queue/online-status', (frame) => {
        logger.debug('[PRESENCE-EVENTS] Received online status queue update', frame);
        try {
          const data = JSON.parse(frame.body);
          logger.debug('[WebSocket] Received online status queue update:', data);
          this.handleOnlineStatusUpdate(data);
        } catch (error) {
          logger.error('❌ [PRESENCE-EVENTS] Error parsing online status queue update:', error);
        }
      });
      this.subscriptions.set('online_status_queue', subscription);
      logger.debug('✅ [PRESENCE-EVENTS] Online status queue subscription created');
    } else {
      logger.debug('ℹ️ [PRESENCE-EVENTS] Already subscribed to online status queue');
    }

    // Subscribe to global presence topic
    if (!this.subscriptions.has('presence_topic')) {
      logger.debug('🔧 [PRESENCE-EVENTS] Subscribing to global presence topic');
      
      const subscription = this.stompClient.subscribe('/topic/online-status', (frame) => {
        try {
          const data = JSON.parse(frame.body);
          logger.debug('📨 [PRESENCE-EVENTS] Received global presence update:', data);
          this.handlePresenceUpdate(data);
        } catch (error) {
          logger.error('❌ [PRESENCE-EVENTS] Error parsing global presence update:', error);
        }
      });
      this.subscriptions.set('presence_topic', subscription);
      logger.debug('✅ [PRESENCE-EVENTS] Global presence topic subscription created');
    } else {
      logger.debug('ℹ️ [PRESENCE-EVENTS] Already subscribed to global presence topic');
    }
  }

  unsubscribeFromPresenceEvents(): void {
    const onlineStatusQueueSub = this.subscriptions.get('online_status_queue');
    if (onlineStatusQueueSub) {
      onlineStatusQueueSub.unsubscribe();
      this.subscriptions.delete('online_status_queue');
      logger.debug('[WebSocket] Unsubscribed from online status queue');
    }

    const presenceTopicSub = this.subscriptions.get('presence_topic');
    if (presenceTopicSub) {
      presenceTopicSub.unsubscribe();
      this.subscriptions.delete('presence_topic');
      logger.debug('[WebSocket] Unsubscribed from presence topic');
    }
  }

  // 🚀 Optimized batch presence operations matching backend API
  subscribeToUserPresence(userIds: string[]): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot subscribe to user presence - not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    this.stompClient.publish({
      destination: '/app/presence.subscribe',
      body: JSON.stringify({ userIds }),
      headers: headers,
    });
    logger.debug('[WebSocket] Subscribed to user presence:', userIds);
  }

  unsubscribeFromUserPresence(userIds: string[]): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot unsubscribe from user presence - not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    this.stompClient.publish({
      destination: '/app/presence.unsubscribe',
      body: JSON.stringify({ userIds }),
      headers: headers,
    });
    logger.debug('[WebSocket] Unsubscribed from user presence:', userIds);
  }

  // STEP 2: Batch request for online status with detailed logging
  requestBatchOnlineStatus(userIds: string[]): void {
    console.log('🔔 [REQUEST-ONLINE] requestBatchOnlineStatus called');
    console.log('🔔 [REQUEST-ONLINE] UserIds to request:', userIds);
    console.log('🔔 [REQUEST-ONLINE] UserIds count:', userIds.length);
    
    if (!this.stompClient?.connected) {
      console.log('❌ [REQUEST-ONLINE] Cannot request batch online status - not connected');
      logger.warn('[WebSocket] Cannot request batch online status - not connected');
      return;
    }

    if (!userIds || userIds.length === 0) {
      console.log('⚠️ [REQUEST-ONLINE] No userIds provided, skipping request');
      logger.warn('[WebSocket] No userIds provided for online status request');
      return;
    }

    // Remove duplicates and filter valid IDs
    const uniqueUserIds = [...new Set(userIds.filter(id => id && id.trim()))];
    console.log('🔔 [REQUEST-ONLINE] Unique userIds after deduplication:', uniqueUserIds);

    const headers = this.getAuthHeaders();
    const payload = { userIds: uniqueUserIds };
    
    console.log('📤 [REQUEST-ONLINE] Sending to destination: /app/request-online-status');
    console.log('📤 [REQUEST-ONLINE] Payload:', payload);
    console.log('📤 [REQUEST-ONLINE] Headers:', headers);
    
    this.stompClient.publish({
      destination: WS_DESTINATIONS.REQUEST_ONLINE_STATUS,
      body: JSON.stringify(payload),
      headers: headers,
    });
    
    console.log('✅ [REQUEST-ONLINE] Successfully sent request to /app/request-online-status');
    console.log('✅ [REQUEST-ONLINE] Requested for users:', uniqueUserIds);
    logger.debug('[WebSocket] Requested batch online status for:', uniqueUserIds);
  }

  // Enhanced session management - matches backend /app/online-status
  setOnlineStatus(isOnline: boolean): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot set online status - not connected');
      return;
    }

    const headers = this.getAuthHeaders();
    this.stompClient.publish({
      destination: '/app/online-status',
      body: JSON.stringify({ isOnline }),
      headers: headers,
    });
    logger.debug('[WebSocket] Set online status:', isOnline);
  }

  // Separate methods for explicit online/offline actions
  goOnline(): void {
    this.setOnlineStatus(true);
    logger.debug('[WebSocket] User went online');
  }

  goOffline(): void {
    this.setOnlineStatus(false);
    logger.debug('[WebSocket] User went offline');
  }

  // 🚀 MAIN FLOW: Initialize after login (follows exact flow requirements)
  initializeAfterLogin(currentUserId: string, sessionId?: string): void {
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot initialize after login - not connected');
      return;
    }
    this.subscribeToPresenceEvents();
    this.sendHeartbeat(undefined, sessionId);
    const allUserIds = [currentUserId];
    const uniqueUserIds = [...new Set(allUserIds.filter(id => id && id.trim()))];
    
    if (uniqueUserIds.length > 0) {
      this.requestBatchOnlineStatus(uniqueUserIds);
    } else {
      console.log('⚠️ [INIT-LOGIN] No valid user IDs to request status for');
    }
    this.subscribeToOnlineStatus((response) => {
      console.log('📨 [INIT-LOGIN] Response timestamp:', response.timestamp);
    });
    
    setTimeout(() => {
      this.logSubscriptionStatus();
    }, 1000);
    
    logger.info('[WebSocket] Post-login initialization completed');
  }

  // 🔄 ROOM FLOW: Update user list when entering a room 
  updateOnlineStatusForRoom(currentUserId: string, roomUserIds: string[]): void {
    if (!this.stompClient?.connected) {
      console.log('❌ [ROOM-UPDATE] Cannot update room status - WebSocket not connected');
      logger.warn('[WebSocket] Cannot update room status - not connected');
      return;
    }

    const allUserIds = [currentUserId, ...roomUserIds];
    const uniqueUserIds = [...new Set(allUserIds.filter(id => id && id.trim()))];
    
    console.log('🏠 [ROOM-UPDATE] Unique user IDs for room (self + participants):', uniqueUserIds);
    
    if (uniqueUserIds.length > 0) {
      this.requestBatchOnlineStatus(uniqueUserIds);
    }
    logger.debug('[WebSocket] Room online status updated for users:', uniqueUserIds);
  }

  // 🚀 Presence lifecycle management (updated for backend compatibility)
  initializePresenceSystem(friendIds: string[] = []): void {
    logger.info('[WebSocket] Initializing presence system');
    
    if (!this.stompClient?.connected) {
      logger.warn('[WebSocket] Cannot initialize presence - not connected');
      return;
    }

    // 1. Subscribe to presence events first
    this.subscribeToPresenceEvents();
    
    // 2. Set user online (uses /app/online-status endpoint)
    this.goOnline();
    
    // 3. Subscribe to friends' presence if provided (uses /app/presence.subscribe)
    if (friendIds.length > 0) {
      this.subscribeToUserPresence(friendIds);
      // Request initial status (uses /app/request-online-status)
      this.requestBatchOnlineStatus(friendIds);
    }
    
    // 4. Start heartbeat (uses /app/heartbeat)
    this.startHeartbeat(30000); // 30 seconds interval, backend session TTL is 60s
    
    logger.debug('[WebSocket] Presence system initialized successfully');
  }

  shutdownPresenceSystem(): void {
    this.stopHeartbeat();
    this.goOffline();
    this.unsubscribeFromPresenceEvents();
    logger.debug('[WebSocket] Presence system shut down');
  }

  // Enhanced heartbeat system
  private heartbeatInterval: NodeJS.Timeout | null = null;

  startHeartbeat(intervalMs: number = 30000): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }

    this.heartbeatInterval = setInterval(() => {
      if (this.stompClient?.connected) {
        this.sendHeartbeat( );
      }
    }, intervalMs);

    logger.debug('[WebSocket] Heartbeat started with interval:', intervalMs);
  }

  stopHeartbeat(): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
      logger.debug('[WebSocket] Heartbeat stopped');
    }
  }

  // 🚀 Enhanced event handlers with better integration
  private handleOnlineStatusUpdate(data: OnlineStatusResponse): void {
    console.log('📨 [DEBUG] Handling online status update:', data);
    logger.debug('[WebSocket] Handling online status update:', data);
    
    // Dispatch custom event for presence updates with detailed data
    const event = new CustomEvent('presence-update', { 
      detail: { 
        type: 'online-status-update',
        data,
        timestamp: Date.now()
      } 
    });
    window.dispatchEvent(event);
  }

  private handlePresenceUpdate(data: any): void {
    logger.debug('[WebSocket] Handling global presence update:', data);
    const event = new CustomEvent('presence-event', { 
      detail: { 
        type: 'global-presence-update',
        data,
        timestamp: Date.now()
      } 
    });
    window.dispatchEvent(event);
  }

  // Method to manually trigger presence status refresh
  refreshPresenceStatus(userIds: string[]): void {
    logger.debug('[WebSocket] Refreshing presence status');
    
    if (userIds.length > 0) {
      this.requestBatchOnlineStatus(userIds);
    }
  }

  // 🧹 Cleanup operations
  unsubscribeFromTyping(conversationId?: string): void {
    if (conversationId) {
      const subscription = this.subscriptions.get(`typing_${conversationId}`);
      if (subscription) {
        subscription.unsubscribe();
        this.subscriptions.delete(`typing_${conversationId}`);
      }
    } else {
      const typingKeys = Array.from(this.subscriptions.keys()).filter(key => key.startsWith('typing_'));
      typingKeys.forEach(key => {
        const subscription = this.subscriptions.get(key);
        if (subscription) {
          subscription.unsubscribe();
          this.subscriptions.delete(key);
        }
      });
    }
  }

  unsubscribeFromOnlineStatus(): void {
    const subscription = this.subscriptions.get('online_status');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('online_status');
    }
  }

  unsubscribeFromPresence(): void {
    const subscription = this.subscriptions.get('presence');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('presence');
    }
  }

  unsubscribeFromNotifications(): void {
    const subscription = this.subscriptions.get('notifications');
    if (subscription) {
      subscription.unsubscribe();
      this.subscriptions.delete('notifications');
    }
  }

  unsubscribeAll(): void {
    this.subscriptions.forEach((subscription) => {
      subscription.unsubscribe();
    });
    this.subscriptions.clear();
  }

  // � Enhanced utility methods for presence management
  isConnected(): boolean {
    return this.stompClient?.connected || false;
  }

  getActiveSubscriptions(): string[] {
    return Array.from(this.subscriptions.keys());
  }

  // Check if presence system is active
  isPresenceSystemActive(): boolean {
    return this.subscriptions.has('online_status_queue') && 
           this.subscriptions.has('presence_topic') &&
           this.heartbeatInterval !== null;
  }

  // Get presence-related subscriptions
  getPresenceSubscriptions(): string[] {
    return this.getActiveSubscriptions().filter(key => 
      key.includes('presence') || 
      key.includes('online_status') || 
      key.includes('heartbeat')
    );
  }

  // 🚀 Enhanced debug method with presence information
  logSubscriptionStatus(): void {
    console.log('🔍 [DEBUG] === Current WebSocket Subscription Status ===');
    console.log('[WebSocket] Connection status:', this.isConnected());
    console.log('[WebSocket] Total subscriptions:', this.subscriptions.size);
    console.log('[WebSocket] Presence system active:', this.isPresenceSystemActive());
    console.log('[WebSocket] Heartbeat active:', this.heartbeatInterval !== null);
    
    // List all current subscriptions
    const allSubscriptions = Array.from(this.subscriptions.keys());
    console.log('[WebSocket] All subscriptions:', allSubscriptions);
    
    // Check specific presence subscriptions
    console.log('🔍 [DEBUG] === Presence Subscription Details ===');
    console.log('online_status subscription:', this.subscriptions.has('online_status') ? '✅ Active' : '❌ Not Found');
    console.log('online_status_queue subscription:', this.subscriptions.has('online_status_queue') ? '✅ Active' : '❌ Not Found');
    console.log('presence_topic subscription:', this.subscriptions.has('presence_topic') ? '✅ Active' : '❌ Not Found');
    console.log('presence_updates subscription:', this.subscriptions.has('presence_updates') ? '✅ Active' : '❌ Not Found');
    
    // Group subscriptions by type
    const subscriptionsByType = {
      conversations: [] as string[],
      typing: [] as string[],
      presence: [] as string[],
      notifications: [] as string[],
      global: [] as string[]
    };
    
    this.subscriptions.forEach((_, key) => {
      if (key.startsWith('conversation_')) {
        subscriptionsByType.conversations.push(key);
      } else if (key.startsWith('typing_')) {
        subscriptionsByType.typing.push(key);
      } else if (key.includes('presence') || key.includes('online_status')) {
        subscriptionsByType.presence.push(key);
      } else if (key.includes('notification')) {
        subscriptionsByType.notifications.push(key);
      } else {
        subscriptionsByType.global.push(key);
      }
    });
    
    console.log('[WebSocket] Subscriptions by type:', subscriptionsByType);
    console.log('🔍 [DEBUG] === End Subscription Status ===');
  }

  // Method kiểm tra subscription cụ thể
  hasSubscription(key: string): boolean {
    return this.subscriptions.has(key);
  }
}

