// src/utils/auth.ts

/**
 * Get authentication token from localStorage
 */
export const getAuthToken = (): string | null => {
  return localStorage.getItem('token');
};

/**
 * Set authentication token to localStorage
 */
export const setAuthToken = (token: string): void => {
  localStorage.setItem('token', token);
};

/**
 * Remove authentication token from localStorage
 */
export const removeAuthToken = (): void => {
  localStorage.removeItem('token');
};

/**
 * Check if user is authenticated
 */
export const isAuthenticated = (): boolean => {
  const token = getAuthToken();
  return token !== null && token.trim().length > 0;
};

/**
 * Decode JWT token (without verification)
 */
export const decodeToken = (token: string): any => {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
    return JSON.parse(jsonPayload);
  } catch (error) {
    console.error('Error decoding token:', error);
    return null;
  }
};

/**
 * Check if token is expired
 */
export const isTokenExpired = (token?: string): boolean => {
  const tokenToCheck = token || getAuthToken();
  if (!tokenToCheck) return true;
  
  const decoded = decodeToken(tokenToCheck);
  if (!decoded || !decoded.exp) return true;
  
  const currentTime = Date.now() / 1000;
  return decoded.exp < currentTime;
};

/**
 * Get user info from token
 */
export const getUserFromToken = (): { userId: string; username: string } | null => {
  const token = getAuthToken();
  if (!token || isTokenExpired(token)) return null;
  
  const decoded = decodeToken(token);
  if (!decoded) return null;
  
  return {
    userId: decoded.userId,
    username: decoded.sub
  };
};

// src/utils/debounce.ts

export function debounce<T extends (...args: any[]) => void>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: NodeJS.Timeout;
  
  return (...args: Parameters<T>) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func(...args), delay);
  };
}

// src/utils/logger.ts

export const LogLevel = {
  ERROR: 0,
  WARN: 1,
  INFO: 2,
  DEBUG: 3
} as const;

export type LogLevel = typeof LogLevel[keyof typeof LogLevel];

class Logger {
  private currentLevel: LogLevel = LogLevel.DEBUG; // Show all logs including debug

  setLevel(level: LogLevel) {
    this.currentLevel = level;
  }

  error(...args: any[]) {
    if (this.currentLevel >= LogLevel.ERROR) {
      console.error(...args);
    }
  }

  warn(...args: any[]) {
    if (this.currentLevel >= LogLevel.WARN) {
      console.warn(...args);
    }
  }

  info(...args: any[]) {
    if (this.currentLevel >= LogLevel.INFO) {
      console.log(...args);
    }
  }

  debug(...args: any[]) {
    if (this.currentLevel >= LogLevel.DEBUG) {
      console.log(...args);
    }
  }
}

export const logger = new Logger();

